const j = $json;
const headers = (j.payload && Array.isArray(j.payload.headers)) ? j.payload.headers : (Array.isArray(j.headers) ? j.headers : []);
const h = (name) => { const f = headers.find(x => x && x.name && String(x.name).toLowerCase() === name.toLowerCase()); return f ? f.value : ''; };
const asStr = (v) => {
  if (!v) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'object') return v.text || (v.value && v.value[0] && (v.value[0].address || v.value[0].name)) || '';
  return String(v);
};
const from = asStr(j.From || j.from || h('From'));
const subject = (asStr(j.Subject || j.subject || h('Subject'))) || '(no subject)';
const snippet = String(j.snippet || j.text || '').slice(0, 6000);
const email_id = j.id || j.messageId || '';
const thread_id = j.threadId || '';
let received_at = '';
const d = j.Date || j.date || h('Date');
if (typeof d === 'string') received_at = d; else if (d) received_at = String(d);
if (!received_at && j.internalDate) { try { received_at = new Date(parseInt(j.internalDate, 10)).toISOString(); } catch (e) {} }
return { json: { email_id, thread_id, from_addr: from, subject, snippet, received_at } };

const j = $json;
const gt = (o) => {
  if (!o) return '';
  if (typeof o === 'string') return o;
  if (typeof o.text === 'string') return o.text;
  if (typeof o.content === 'string') return o.content;
  const c = (o.content && typeof o.content === 'object') ? o.content : o;
  if (c && Array.isArray(c.parts)) return c.parts.map(p => (p && p.text) ? p.text : '').join('');
  if (Array.isArray(o.parts)) return o.parts.map(p => (p && p.text) ? p.text : '').join('');
  if (o.message) return gt(o.message);
  return '';
};
let raw = gt(j);
if (typeof raw !== 'string') raw = JSON.stringify(raw);
let data = {}; let parseOk = true;
try {
  const c = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  const s = c.indexOf('{'); const e = c.lastIndexOf('}');
  data = JSON.parse(s >= 0 ? c.slice(s, e + 1) : c);
} catch (err) { parseOk = false; }
const worthy = !parseOk ? true : (data.worthy === true || String(data.worthy).toLowerCase() === 'true');
const email = $('Normalize Email').item.json;
return { json: {
  worthy: worthy,
  category: data.category || 'other',
  priority: data.priority || 'normal',
  summary: data.summary || email.subject || '',
  reason: parseOk ? (data.reason || '') : 'classifier output unparseable - forwarded to be safe',
  email_id: email.email_id,
  thread_id: email.thread_id,
  from_addr: email.from_addr,
  subject: email.subject,
  snippet: email.snippet,
  received_at: email.received_at
} };

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  let msg = null, meta = {};
  const dig = (o) => {
    if (!o || typeof o !== 'object') return;
    if (o.metadata && (o.metadata.phone_number_id || o.metadata.display_phone_number)) meta = o.metadata;
    if (Array.isArray(o.messages) && o.messages.length && !msg) msg = o.messages[0];
    if (Array.isArray(o.entry)) o.entry.forEach(e => dig(e));
    if (Array.isArray(o.changes)) o.changes.forEach(c => dig(c.value));
    if (o.value) dig(o.value);
  };
  dig(j);
  if (!msg && (j.type || j.from)) msg = j;
  msg = msg || {};
  if (!msg.from) continue;
  const type = msg.type || '';
  let text = '';
  if (type === 'text' && msg.text) text = msg.text.body || '';
  if (type === 'button' && msg.button) text = msg.button.text || '';
  if (type === 'interactive' && msg.interactive) { const it = msg.interactive; text = (it.button_reply && it.button_reply.title) || (it.list_reply && it.list_reply.title) || ''; }
  let audioId = '', audioMime = '';
  if (type === 'audio' && msg.audio) { audioId = msg.audio.id || ''; audioMime = msg.audio.mime_type || 'audio/ogg'; }
  const contextId = (msg.context && msg.context.id) ? msg.context.id : '';
  out.push({ json: { sender: msg.from || '', phoneNumberId: meta.phone_number_id || '', messageId: msg.id || '', type: type, text: text, isVoice: type === 'audio', audioId: audioId, audioMime: audioMime, contextId: contextId, raw_preview: JSON.stringify(j).slice(0, 600) } });
}
return out;

const prep = $('Prep Instruction').first().json;
const contextId = (prep && prep.contextId) ? String(prep.contextId).trim() : '';
const instruction = (prep && prep.instruction) ? prep.instruction : '';
const sd = $getWorkflowStaticData('global');
const draftMap = (sd && sd.draftMap) ? sd.draftMap : {};
const allRows = $('Get Current Email').all().map(i => i.json).filter(r => r && r.email_id);
const alertedRows = allRows.filter(r => r.status === 'alerted');
alertedRows.sort((a,b) => String(a.createdAt||'').localeCompare(String(b.createdAt||'')));
const rowById = (id) => allRows.find(r => r.email_id === id);
const mk = (t, mode) => [{ json: { has_target: mode === 'ok', mode: mode || 'ok', instruction, email_id: t.email_id, thread_id: t.thread_id, recipient: t.from_addr, subject: t.subject, snippet: t.snippet } }];
const note = (mode, extra) => [{ json: Object.assign({ has_target: false, mode: mode, instruction: instruction }, extra || {}) }];
if (contextId && draftMap[contextId]) {
  const eid = draftMap[contextId];
  const row = rowById(eid);
  if (row) {
    if (row.status === 'alerted') return mk(row, 'ok');
    if (row.status === 'replied') return note('none', { reason: 'already_sent', email_id: eid, subject: row.subject });
    if (row.status === 'dismissed') return note('none', { reason: 'already_dismissed', email_id: eid, subject: row.subject });
  }
}
if (contextId) {
  const arow = allRows.find(r => r.wa_message_id === contextId);
  if (arow) {
    if (arow.status === 'alerted') return mk(arow, 'ok');
    if (arow.status === 'replied') return note('none', { reason: 'already_sent', email_id: arow.email_id, subject: arow.subject });
    if (arow.status === 'dismissed') return note('none', { reason: 'already_dismissed', email_id: arow.email_id, subject: arow.subject });
  }
}
const m = instruction.trim().match(/^#?\s*(\d+)\s*$/);
if (m && alertedRows.length > 1) { const idx = parseInt(m[1],10) - 1; if (idx >= 0 && idx < alertedRows.length) return mk(alertedRows[idx], 'ok'); }
if (alertedRows.length === 1) return mk(alertedRows[0], 'ok');
if (alertedRows.length === 0) return note('none', { reason: 'nothing' });
const list = alertedRows.map((r,i) => (i+1) + ') ' + (r.subject || '(no subject)') + ' — ' + (r.from_addr || '')).join('\n');
return note('ambiguous', { count: alertedRows.length, list: list });

