Reply with the number, or swipe-reply the alert you mean.

parameters.jsCode:
const pick = $('Pick Active Email').first().json;
const instr = String(pick.instruction || '').trim().toLowerCase().replace(/[.!\s]+$/,'').trim();
let fed = {}; try { fed = $('Find Existing Draft').first().json || {}; } catch(e){}
const awaiting = !!(fed && fed.state === 'awaiting_approval' && fed.draft_text);
let quick = 'defer';
const VAGUE = ['ok','k','kk','okay','okey','cool','thanks','thank you','ty','sure','great','nice','got it','yep','yup','👍','👌','🙏'];
if (VAGUE.includes(instr)) quick = 'unclear';
else if (awaiting && /^(confirm|send|send it|send that|yes send it|go ahead( and)? send|looks good,? send( it)?|send the reply)$/.test(instr)) quick = 'confirm';
else if (awaiting && /^(cancel|cancel that|never ?mind|nevermind|forget it|drop it|stop|scratch that|don'?t send( it)?)$/.test(instr)) quick = 'cancel';
else if (/^(skip|skip this|skip this one|ignore|ignore this|ignore this email|dismiss|dismiss this|not replying|not replying to (this|that)|leave it)$/.test(instr)) quick = 'dismiss';
return [{ json: { quick_intent: quick } }];

const intent = String($input.first().json.quick_intent || 'unclear');
const pick = $('Pick Active Email').first().json;
let draft_text = '';
try { const fed = $('Find Existing Draft').first().json; if (fed && fed.state === 'awaiting_approval' && fed.draft_text) draft_text = fed.draft_text; } catch (e) {}
const raw2 = String(pick.recipient || '');
let email = '';
const m = raw2.match(/<([^>]+)>/);
if (m) { email = m[1]; } else { const m2 = raw2.match(/[^\s<>]+@[^\s<>]+/); email = m2 ? m2[0] : raw2; }
email = email.trim().toLowerCase();
let fin = intent;
if (fin === 'confirm' && !draft_text) fin = 'unclear';
if (fin === 'cancel' && !draft_text) fin = 'unclear';
return [{ json: { intent: fin, email_id: pick.email_id, thread_id: pick.thread_id, recipient: pick.recipient, recipient_email: email, subject: pick.subject, snippet: pick.snippet, instruction: pick.instruction, draft_text: draft_text } }];

const sd = $getWorkflowStaticData('global');
sd.draftMap = sd.draftMap || {};
let mid = '';
try { const j = $json; mid = (j && j.messages && j.messages[0] && j.messages[0].id) ? j.messages[0].id : (j && j.id ? j.id : (j && j.messageId ? j.messageId : '')); } catch (e) {}
let eid = '';
try { eid = $('Extract Draft').item.json.email_id || ''; } catch (e) {}
if (mid && eid) {
  sd.draftMap[mid] = eid;
  const keys = Object.keys(sd.draftMap);
  if (keys.length > 200) { for (const k of keys.slice(0, keys.length - 200)) { delete sd.draftMap[k]; } }
}
return [{ json: { indexed_msg_id: mid, email_id: eid } }];
